import { supabase } from './supabase'
import type { Json } from '@/types/db'

export const TENSES = [
  'present_indefinite',
  'past_indefinite',
  'conditional_present',
  'imperative',
  'future_periphrastic'
] as const

export type Tense = (typeof TENSES)[number]

export const TENSE_LABEL: Record<Tense, string> = {
  present_indefinite:  'Präsens',
  past_indefinite:     'Vergangenheit',
  conditional_present: 'Konditional',
  imperative:          'Imperativ',
  future_periphrastic: 'Zukunft'
}

export const PERSONS = ['1sg', '2sg', '3sg', '1pl', '2pl', '3pl'] as const
export type Person = (typeof PERSONS)[number]

export const PERSON_LABEL: Record<Person, string> = {
  '1sg': 'én',
  '2sg': 'te',
  '3sg': 'ő',
  '1pl': 'mi',
  '2pl': 'ti',
  '3pl': 'ők'
}

export const PERSON_DE: Record<Person, string> = {
  '1sg': 'ich',
  '2sg': 'du',
  '3sg': 'er/sie/es',
  '1pl': 'wir',
  '2pl': 'ihr',
  '3pl': 'sie'
}

// ============================================================================

export type VerbRow = {
  id: number
  infinitive: string
  infinitive_de: string
  verb_type: string | null
  is_ikes: boolean
  is_irregular: boolean
  conjugations: Record<Tense, Record<Person, string | null>> | null
  example_hu: string | null
  example_de: string | null
  category: string | null
}

export type TenseMastery = {
  correct: number
  wrong: number
  streak: number
  mastered_at: string | null
}

export type VerbProgress = {
  id: number
  user_id: string
  verb_id: number
  mastery: Partial<Record<Tense, TenseMastery>>
}

export const EMPTY_TENSE_MASTERY: TenseMastery = {
  correct: 0,
  wrong: 0,
  streak: 0,
  mastered_at: null
}

const MASTERY_THRESHOLD_STREAK = 5

// ============================================================================

export async function loadVerbs(): Promise<VerbRow[]> {
  const { data, error } = await supabase
    .from('verbs_medical')
    .select('id, infinitive, infinitive_de, verb_type, is_ikes, is_irregular, conjugations, example_hu, example_de, category')
    .order('infinitive')
  if (error) throw error
  return (data ?? []) as unknown as VerbRow[]
}

export async function loadVerbProgress(userId: string): Promise<Map<number, VerbProgress>> {
  const { data } = await supabase
    .from('verb_progress_medical')
    .select('id, user_id, verb_id, mastery')
    .eq('user_id', userId)
  const map = new Map<number, VerbProgress>()
  for (const row of (data ?? []) as VerbProgress[]) {
    map.set(row.verb_id, row)
  }
  return map
}

/**
 * Updated mastery counts for a single tense and persists to DB.
 * Returns true if the tense JUST crossed the mastery threshold (for XP-Bonus + Achievement).
 */
export async function recordVerbAttempt(
  userId: string,
  verbId: number,
  tense: Tense,
  isCorrect: boolean
): Promise<{ justMastered: boolean }> {
  const { data: existing } = await supabase
    .from('verb_progress_medical')
    .select('id, mastery')
    .eq('user_id', userId)
    .eq('verb_id', verbId)
    .maybeSingle()

  type Row = { id: number; mastery: Partial<Record<Tense, TenseMastery>> } | null
  const row = existing as Row

  const masteryMap: Partial<Record<Tense, TenseMastery>> = { ...(row?.mastery ?? {}) }
  const cur = masteryMap[tense] ?? { ...EMPTY_TENSE_MASTERY }

  const next: TenseMastery = {
    correct: cur.correct + (isCorrect ? 1 : 0),
    wrong: cur.wrong + (isCorrect ? 0 : 1),
    streak: isCorrect ? cur.streak + 1 : 0,
    mastered_at: cur.mastered_at
  }

  let justMastered = false
  if (next.streak >= MASTERY_THRESHOLD_STREAK && !next.mastered_at) {
    next.mastered_at = new Date().toISOString()
    justMastered = true
  }

  masteryMap[tense] = next

  if (row) {
    await supabase
      .from('verb_progress_medical')
      .update({
        mastery: masteryMap as unknown as Json,
        last_reviewed_at: new Date().toISOString()
      })
      .eq('id', row.id)
  } else {
    await supabase.from('verb_progress_medical').insert({
      user_id: userId,
      verb_id: verbId,
      mastery: masteryMap as unknown as Json,
      last_reviewed_at: new Date().toISOString()
    })
  }

  return { justMastered }
}

/**
 * Filter verbs that have at least one non-null person form for the given tense.
 * Useful for excluding the 4 verbs (bevesz, enyhít, ...) that the scraper missed.
 */
export function hasUsableTense(verb: VerbRow, tense: Tense): boolean {
  const t = verb.conjugations?.[tense]
  if (!t) return false
  return PERSONS.some((p) => t[p])
}

export function pickRandomPerson(verb: VerbRow, tense: Tense): Person | null {
  const t = verb.conjugations?.[tense]
  if (!t) return null
  const candidates = PERSONS.filter((p) => t[p])
  if (candidates.length === 0) return null
  return candidates[Math.floor(Math.random() * candidates.length)]
}
